            'is_read': self.is_read,
        }


class CodeRepository:
    """Represents a code repository with version control."""

    def __init__(self, project_id, name):
        self.id = str(uuid.uuid4())
        self.project_id = project_id
        self.name = name
        self.files = {}
        self.commits = []
        self.branches = {'main': []}
        self.current_branch = 'main'
        self.created_at = datetime.now()

    def add_file(self, filename, content, author_id):
        self.files[filename] = {
            'content': content,
            'last_modified': datetime.now().isoformat(),
            'author_id': author_id,
        }
        return True

    def update_file(self, filename, content, author_id):
        if filename not in self.files:
            return False, "File not found"
        self.files[filename] = {
            'content': content,
            'last_modified': datetime.now().isoformat(),
            'author_id': author_id,
        }
        return True, "File updated"

    def delete_file(self, filename):
        if filename not in self.files:
            return False, "File not found"
        del self.files[filename]
        return True, "File deleted"

    def commit(self, message, author_id, files_changed=None):
        commit_entry = {
            'id': str(uuid.uuid4()),
            'message': message,
            'author_id': author_id,
            'timestamp': datetime.now().isoformat(),
            'branch': self.current_branch,
            'files_changed': files_changed or [],
        }
        self.commits.append(commit_entry)
        self.branches[self.current_branch].append(commit_entry['id'])
        return commit_entry

    def create_branch(self, branch_name):
        if branch_name in self.branches:
            return False, "Branch already exists"
        self.branches[branch_name] = list(self.branches[self.current_branch])
        return True, f"Branch '{branch_name}' created"

    def switch_branch(self, branch_name):
        if branch_name not in self.branches:
            return False, "Branch not found"
        self.current_branch = branch_name
        return True, f"Switched to branch '{branch_name}'"

    def get_commit_history(self, branch=None):
        branch = branch or self.current_branch
        if branch not in self.branches:
            return []
        branch_commit_ids = self.branches[branch]
        return [c for c in self.commits if c['id'] in branch_commit_ids]

    def to_dict(self):
        return {
            'id': self.id,
            'project_id': self.project_id,
            'name': self.name,
            'files': list(self.files.keys()),
            'branches': list(self.branches.keys()),
            'current_branch': self.current_branch,
            'commit_count': len(self.commits),
        }


