class UserService:
    """Service for managing user accounts and profiles."""

    def __init__(self):
        self.users = {}
        self.usernames = {}
        self.emails = {}

    def create_user(self, username, email, password, name=""):
        errors = self._validate_user_input(username, email, password, name)
        if errors:
            return None, errors

        if username.lower() in self.usernames:
            return None, ["Username already taken"]
        if email.lower() in self.emails:
            return None, ["Email already registered"]

        user = User(username, email, password, name)
        self.users[user.id] = user
        self.usernames[username.lower()] = user.id
        self.emails[email.lower()] = user.id
        return user, []

    def _validate_user_input(self, username, email, password, name=""):
        errors = []
        if not username or not username.strip():
            errors.append("Username is required")
        elif len(username) < 3:
            errors.append("Username must be at least 3 characters")
        elif len(username) > 50:
            errors.append("Username must be at most 50 characters")
        elif not re.match(r'^[a-zA-Z0-9_]+$', username):
            errors.append("Username can only contain letters, numbers, and underscores")

        if not email or not email.strip():
            errors.append("Email is required")
        elif not User.EMAIL_REGEX.match(email):
            errors.append("Invalid email format")

        if not password:
            errors.append("Password is required")
        elif len(password) < 8:
            errors.append("Password must be at least 8 characters")

        if name and len(name) > User.MAX_NAME_LENGTH:
            errors.append(f"Name must be at most {User.MAX_NAME_LENGTH} characters")

        return errors

    def get_user(self, user_id):
        return self.users.get(user_id)

    def get_user_by_username(self, username):
        user_id = self.usernames.get(username.lower())
        return self.users.get(user_id) if user_id else None

    def update_user(self, user_id, **kwargs):
        user = self.users.get(user_id)
        if not user:
            return None, ["User not found"]

        if 'bio' in kwargs and len(kwargs['bio']) > User.MAX_BIO_LENGTH:
            return None, [f"Bio must be at most {User.MAX_BIO_LENGTH} characters"]

        if 'name' in kwargs and len(kwargs['name']) > User.MAX_NAME_LENGTH:
            return None, [f"Name must be at most {User.MAX_NAME_LENGTH} characters"]

        user.update_profile(**kwargs)
        return user, []

    def delete_user(self, user_id):
        user = self.users.get(user_id)
        if not user:
            return False, "User not found"
        user.is_active = False
        return True, "User deactivated"

    def authenticate(self, username, password):
        user = self.get_user_by_username(username)
        if not user or not user.is_active:
            return None
        if user.verify_password(password):
            return user
        return None

    def search_users(self, skills=None, interests=None, query=None):
        results = []
        for user in self.users.values():
            if not user.is_active:
                continue
            if query:
                q = query.lower()
                if (q not in user.username.lower() and
                        q not in user.name.lower() and
                        q not in user.bio.lower()):
                    continue
            if skills:
                search_skills = [s.strip().lower() for s in skills]
                if not any(s in user.skills for s in search_skills):
                    continue
            if interests:
                search_interests = [i.strip().lower() for i in interests]
                if not any(i in user.interests for i in search_interests):
                    continue
            results.append(user)
        return results

    def get_all_users(self):
        return [u for u in self.users.values() if u.is_active]


class ProjectService:
    """Service for managing projects."""

    def __init__(self):
        self.projects = {}

    def create_project(self, title, description, owner_id, required_skills=None):
        errors = self._validate_project_input(title, description)
        if errors:
            return None, errors

        project = Project(title, description, owner_id, required_skills)
        self.projects[project.id] = project
        return project, []

    def _validate_project_input(self, title, description):
        errors = []
        if not title or not title.strip():
            errors.append("Project title is required")
        elif len(title) > Project.MAX_TITLE_LENGTH:
            errors.append(f"Title must be at most {Project.MAX_TITLE_LENGTH} characters")

        if not description or not description.strip():
            errors.append("Project description is required")
        elif len(description) > Project.MAX_DESCRIPTION_LENGTH:
            errors.append(f"Description must be at most {Project.MAX_DESCRIPTION_LENGTH} characters")

        return errors

    def get_project(self, project_id):
        return self.projects.get(project_id)

    def update_project(self, project_id, requester_id, **kwargs):
        project = self.projects.get(project_id)
        if not project:
            return None, ["Project not found"]
        if requester_id != project.owner_id:
            return None, ["Only the project owner can update project settings"]

        if 'title' in kwargs:
            if not kwargs['title'] or not kwargs['title'].strip():
                return None, ["Project title is required"]
            if len(kwargs['title']) > Project.MAX_TITLE_LENGTH:
                return None, [f"Title must be at most {Project.MAX_TITLE_LENGTH} characters"]
            project.title = kwargs['title']

        if 'description' in kwargs:
            if len(kwargs['description']) > Project.MAX_DESCRIPTION_LENGTH:
                return None, [f"Description exceeds max length"]
            project.description = kwargs['description']

        if 'required_skills' in kwargs:
            project.required_skills = [s.strip().lower() for s in kwargs['required_skills']]

        if 'tags' in kwargs:
            project.tags = kwargs['tags']

        if 'max_members' in kwargs:
            project.max_members = kwargs['max_members']

        project.updated_at = datetime.now()
        return project, []

    def delete_project(self, project_id, requester_id):
        project = self.projects.get(project_id)
        if not project:
            return False, "Project not found"
        if requester_id != project.owner_id:
            return False, "Only the project owner can delete the project"
        project.set_status('archived')
        return True, "Project archived"

    def search_projects(self, skills=None, status=None, query=None, tags=None):
        results = []
        for project in self.projects.values():
            if project.status == 'archived':
                continue
            if status and project.status != status:
                continue
            if query:
                q = query.lower()
                if (q not in project.title.lower() and
                        q not in project.description.lower()):
                    continue
            if skills:
                search_skills = [s.strip().lower() for s in skills]
                if not any(s in project.required_skills for s in search_skills):
                    continue
            if tags:
                search_tags = [t.strip().lower() for t in tags]
                if not any(t in [pt.lower() for pt in project.tags] for t in search_tags):
                    continue
            results.append(project)
        return results

    def get_user_projects(self, user_id):
        return [p for p in self.projects.values()
                if user_id in p.members and p.status != 'archived']

    def get_all_projects(self):
        return [p for p in self.projects.values() if p.status != 'archived']


class MatchingService:
    """Service for matching users to projects based on skills and interests."""

    def __init__(self, user_service, project_service):
        self.user_service = user_service
        self.project_service = project_service

    def calculate_match_score(self, user, project):
        """Calculate a match score between a user and a project (0-100)."""
        if not user.skills and not project.required_skills:
            return 50

        score = 0
        total_weight = 0

        # Skill matching (weight: 60%)
        if project.required_skills:
            skill_matches = sum(1 for s in user.skills if s in project.required_skills)
            skill_score = (skill_matches / len(project.required_skills)) * 100
            score += skill_score * 0.6
            total_weight += 0.6
        else:
            total_weight += 0.6
            score += 50 * 0.6

        # Interest matching (weight: 25%)
        if project.tags:
            interest_matches = sum(1 for i in user.interests
                                   if i in [t.lower() for t in project.tags])
            if user.interests:
                interest_score = (interest_matches / len(user.interests)) * 100
            else:
                interest_score = 0
            score += interest_score * 0.25
            total_weight += 0.25
        else:
            total_weight += 0.25
            score += 25 * 0.25

        # Project status bonus (weight: 15%)
        status_scores = {
            'planning': 80,
            'active': 100,
            'paused': 40,
            'completed': 10,
        }
        status_score = status_scores.get(project.status, 50)
        score += status_score * 0.15
        total_weight += 0.15

        if total_weight > 0:
            return min(100, score / total_weight * total_weight / 1.0)
        return 0

    def get_project_recommendations(self, user_id, limit=10):
        """Get recommended projects for a user based on their profile."""
        user = self.user_service.get_user(user_id)
        if not user:
            return []

        recommendations = []
        for project in self.project_service.get_all_projects():
            if user_id in project.members:
                continue
            score = self.calculate_match_score(user, project)
            recommendations.append({
                'project': project,
                'score': round(score, 2),
            })

        recommendations.sort(key=lambda x: x['score'], reverse=True)
        return recommendations[:limit]

    def get_team_member_recommendations(self, project_id, limit=10):
        """Get recommended team members for a project."""
        project = self.project_service.get_project(project_id)
        if not project:
            return []

        recommendations = []
        for user in self.user_service.get_all_users():
            if user.id in project.members:
                continue
            score = self.calculate_match_score(user, project)
            recommendations.append({
                'user': user,
                'score': round(score, 2),
            })

        recommendations.sort(key=lambda x: x['score'], reverse=True)
        return recommendations[:limit]


class MessagingService:
    """Service for managing messages between users."""

    def __init__(self):
        self.messages = {}
        self.conversations = defaultdict(list)
        self.project_channels = defaultdict(list)

    def send_message(self, sender_id, recipient_id, content, project_id=None):
        errors = self._validate_message(content)
        if errors:
            return None, errors

        message = Message(sender_id, recipient_id, content, project_id)
        self.messages[message.id] = message

        if project_id:
            self.project_channels[project_id].append(message.id)
        else:
            conv_key = self._get_conversation_key(sender_id, recipient_id)
            self.conversations[conv_key].append(message.id)

        return message, []

    def _validate_message(self, content):
        errors = []
        if not content or not content.strip():
            errors.append("Message content cannot be empty")
        elif len(content) > Message.MAX_CONTENT_LENGTH:
            errors.append(f"Message exceeds maximum length of {Message.MAX_CONTENT_LENGTH}")
        return errors

    def _get_conversation_key(self, user1_id, user2_id):
        return tuple(sorted([user1_id, user2_id]))

    def get_conversation(self, user1_id, user2_id):
        conv_key = self._get_conversation_key(user1_id, user2_id)
        message_ids = self.conversations.get(conv_key, [])
        return [self.messages[mid] for mid in message_ids if mid in self.messages]

    def get_project_messages(self, project_id):
        message_ids = self.project_channels.get(project_id, [])
        return [self.messages[mid] for mid in message_ids if mid in self.messages]

    def get_unread_messages(self, user_id):
        unread = []
        for msg in self.messages.values():
            if msg.recipient_id == user_id and not msg.is_read:
                unread.append(msg)
        return unread

    def mark_as_read(self, message_id, user_id):
        message = self.messages.get(message_id)
        if not message:
            return False, "Message not found"
        if message.recipient_id != user_id:
            return False, "Cannot mark someone else's message as read"
        message.mark_as_read()
        return True, "Message marked as read"

    def get_message_count(self, user_id):
        sent = sum(1 for m in self.messages.values() if m.sender_id == user_id)
        received = sum(1 for m in self.messages.values() if m.recipient_id == user_id)
        unread = sum(1 for m in self.messages.values()
                     if m.recipient_id == user_id and not m.is_read)
        return {'sent': sent, 'received': received, 'unread': unread}


class CodeRepositoryService:
    """Service for managing code repositories."""

    def __init__(self):
        self.repositories = {}
        self.project_repos = {}

    def create_repository(self, project_id, name):
        if not name or not name.strip():
            return None, ["Repository name is required"]

        repo = CodeRepository(project_id, name)
        self.repositories[repo.id] = repo
        if project_id not in self.project_repos:
            self.project_repos[project_id] = []
        self.project_repos[project_id].append(repo.id)
        return repo, []

    def get_repository(self, repo_id):
        return self.repositories.get(repo_id)

    def get_project_repositories(self, project_id):
        repo_ids = self.project_repos.get(project_id, [])
        return [self.repositories[rid] for rid in repo_ids if rid in self.repositories]

    def add_file(self, repo_id, filename, content, author_id):
        repo = self.repositories.get(repo_id)
        if not repo:
            return False, "Repository not found"
        if not filename or not filename.strip():
            return False, "Filename is required"
        repo.add_file(filename, content, author_id)
        return True, "File added"

    def commit_changes(self, repo_id, message, author_id, files_changed=None):
        repo = self.repositories.get(repo_id)
        if not repo:
            return None, "Repository not found"
        if not message or not message.strip():
            return None, "Commit message is required"
        commit = repo.commit(message, author_id, files_changed)
        return commit, "Commit successful"


class TaskService:
    """Service for managing tasks on project boards."""

    def __init__(self):
        self.tasks = {}
        self.project_tasks = defaultdict(list)

    def create_task(self, title, project_id, creator_id, description="",
                    priority="medium", assignee_id=None):
        errors = self._validate_task(title, priority)
        if errors:
            return None, errors

        task = Task(title, project_id, creator_id, description, priority, assignee_id)
        self.tasks[task.id] = task
        self.project_tasks[project_id].append(task.id)
        return task, []

    def _validate_task(self, title, priority):
        errors = []
        if not title or not title.strip():
            errors.append("Task title is required")
        elif len(title) > 200:
            errors.append("Task title must be at most 200 characters")
        if priority not in Task.VALID_PRIORITIES:
            errors.append(f"Invalid priority. Must be one of: {Task.VALID_PRIORITIES}")
        return errors

    def get_task(self, task_id):
        return self.tasks.get(task_id)

    def get_project_tasks(self, project_id, status=None, assignee_id=None):
        task_ids = self.project_tasks.get(project_id, [])
        tasks = [self.tasks[tid] for tid in task_ids if tid in self.tasks]
        if status:
            tasks = [t for t in tasks if t.status == status]
        if assignee_id:
            tasks = [t for t in tasks if t.assignee_id == assignee_id]
        return tasks

    def update_task(self, task_id, **kwargs):
        task = self.tasks.get(task_id)
        if not task:
            return None, ["Task not found"]

        if 'status' in kwargs:
            success, msg = task.set_status(kwargs['status'])
            if not success:
                return None, [msg]

        if 'priority' in kwargs:
            success, msg = task.set_priority(kwargs['priority'])
            if not success:
                return None, [msg]

        if 'assignee_id' in kwargs:
            task.assign(kwargs['assignee_id'])

        if 'title' in kwargs:
            task.title = kwargs['title']

        if 'description' in kwargs:
            task.description = kwargs['description']

        if 'due_date' in kwargs:
            task.due_date = kwargs['due_date']

        if 'labels' in kwargs:
            task.labels = kwargs['labels']

        task.updated_at = datetime.now()
        return task, []

    def delete_task(self, task_id):
        if task_id not in self.tasks:
            return False, "Task not found"
        task = self.tasks[task_id]
        self.project_tasks[task.project_id].remove(task_id)
        del self.tasks[task_id]
        return True, "Task deleted"

    def get_task_statistics(self, project_id):
        tasks = self.get_project_tasks(project_id)
        stats = {status: 0 for status in Task.VALID_STATUSES}
        for task in tasks:
            stats[task.status] += 1
        stats['total'] = len(tasks)
        return stats


# =============================================================================
# Application Facade
# =============================================================================

class CollaborateCraft:
    """Main application facade that coordinates all services."""

    def __init__(self):
        self.user_service = UserService()
        self.project_service = ProjectService()
        self.messaging_service = MessagingService()
        self.code_repo_service = CodeRepositoryService()
        self.task_service = TaskService()
        self.matching_service = MatchingService(
            self.user_service, self.project_service
        )

    # User operations
    def register_user(self, username, email, password, name=""):
        return self.user_service.create_user(username, email, password, name)

    def login(self, username, password):
        return self.user_service.authenticate(username, password)

    def get_user_profile(self, user_id):
        user = self.user_service.get_user(user_id)
        if user:
            return user.to_dict()
        return None

    def update_user_profile(self, user_id, **kwargs):
        return self.user_service.update_user(user_id, **kwargs)

    # Project operations
    def create_project(self, title, description, owner_id, required_skills=None):
        return self.project_service.create_project(
            title, description, owner_id, required_skills
        )

    def join_project(self, project_id, user_id):
        project = self.project_service.get_project(project_id)
        if not project:
            return False, "Project not found"
        return project.add_member(user_id)

    def leave_project(self, project_id, user_id):
        project = self.project_service.get_project(project_id)
        if not project:
            return False, "Project not found"
        if user_id == project.owner_id:
            return False, "Owner cannot leave the project"
        if user_id not in project.members:
            return False, "User is not a member"
        project.members.remove(user_id)
        return True, "Left project successfully"

    # Search and matching
    def search_projects(self, **kwargs):
        return self.project_service.search_projects(**kwargs)

    def search_users(self, **kwargs):
        return self.user_service.search_users(**kwargs)

    def get_project_recommendations(self, user_id, limit=10):
        return self.matching_service.get_project_recommendations(user_id, limit)

    def get_team_recommendations(self, project_id, limit=10):
        return self.matching_service.get_team_member_recommendations(project_id, limit)

    # Messaging
    def send_message(self, sender_id, recipient_id, content, project_id=None):
        return self.messaging_service.send_message(
            sender_id, recipient_id, content, project_id
        )

    def get_conversation(self, user1_id, user2_id):
        return self.messaging_service.get_conversation(user1_id, user2_id)

    def get_project_messages(self, project_id):
        return self.messaging_service.get_project_messages(project_id)

    # Code repository
    def create_repository(self, project_id, name):
        return self.code_repo_service.create_repository(project_id, name)

    def add_file_to_repo(self, repo_id, filename, content, author_id):
        return self.code_repo_service.add_file(repo_id, filename, content, author_id)

    def commit_to_repo(self, repo_id, message, author_id, files_changed=None):
        return self.code_repo_service.commit_changes(
            repo_id, message, author_id, files_changed
        )

    # Task management
    def create_task(self, title, project_id, creator_id, **kwargs):
        return self.task_service.create_task(title, project_id, creator_id, **kwargs)

    def get_project_tasks(self, project_id, **kwargs):
        return self.task_service.get_project_tasks(project_id, **kwargs)

    def update_task(self, task_id, **kwargs):
        return self.task_service.update_task(task_id, **kwargs)


