class TestIntegration(unittest.TestCase):
    """Integration tests for end-to-end workflows."""

    def test_full_collaboration_workflow(self):
        app = CollaborateCraft()

        # Register users
        alice, _ = app.register_user(
            "alice", "alice@example.com", "password123", "Alice Dev"
        )
        alice.add_skill("python")
        alice.add_skill("django")

        bob, _ = app.register_user(
            "bob", "bob@example.com", "password123", "Bob Coder"
        )
        bob.add_skill("python")
        bob.add_skill("testing")

        # Alice creates a project
        project, _ = app.create_project(
            "WebApp", "A collaborative web application",
            alice.id, ["python", "django", "testing"]
        )

        # Bob finds and joins the project
        recommendations = app.get_project_recommendations(bob.id)
        self.assertTrue(len(recommendations) > 0)
        app.join_project(project.id, bob.id)
        self.assertIn(bob.id, project.members)

        # Set up code repository
        repo, _ = app.create_repository(project.id, "webapp-repo")
        app.add_file_to_repo(repo.id, "app.py", "from flask import Flask", alice.id)
        app.commit_to_repo(repo.id, "Initial setup", alice.id, ["app.py"])

        # Create tasks
        task1, _ = app.create_task(
            "Setup database", project.id, alice.id,
            assignee_id=alice.id, priority="high"
        )
        task2, _ = app.create_task(
            "Write tests", project.id, alice.id,
            assignee_id=bob.id, priority="medium"
        )

        # Team communication
        app.send_message(alice.id, bob.id, "Welcome to the project!")
        app.send_message(
            bob.id, alice.id, "Thanks! I'll start on the tests.",
            project_id=project.id
        )

        # Complete tasks
        app.update_task(task1.id, status="done")
        app.update_task(task2.id, status="in_progress")

        # Verify final state
        stats = app.task_service.get_task_statistics(project.id)
        self.assertEqual(stats['done'], 1)
        self.assertEqual(stats['in_progress'], 1)
        self.assertEqual(len(project.members), 2)

    def test_project_lifecycle(self):
        app = CollaborateCraft()

        owner, _ = app.register_user(
            "owner", "owner@example.com", "password123"
        )
        project, _ = app.create_project(
            "Lifecycle Test", "Testing project lifecycle", owner.id
        )

        # Planning → Active
        project.set_status('active')
        self.assertEqual(project.status, 'active')

        # Add milestones
        m1 = project.add_milestone("MVP", description="Minimum viable product")
        m2 = project.add_milestone("Beta", description="Beta release")

        # Complete milestone
        project.update_milestone(m1['id'], status='completed')

        # Pause and resume
        project.set_status('paused')
        self.assertEqual(project.status, 'paused')
        project.set_status('active')

        # Complete project
        project.set_status('completed')
        self.assertEqual(project.status, 'completed')


