def main():
    """Run all tests and demonstrate the application."""
    print("=" * 70)
    print("CollaborateCraft - Social Networking Platform for Coding Collaboration")
    print("=" * 70)
    print()

    # Run tests
    loader = unittest.TestLoader()
    suite = unittest.TestSuite()

    suite.addTests(loader.loadTestsFromTestCase(TestUserProfileCreation))
    suite.addTests(loader.loadTestsFromTestCase(TestProjectCreation))
    suite.addTests(loader.loadTestsFromTestCase(TestSearchAndMatching))
    suite.addTests(loader.loadTestsFromTestCase(TestCollaborationTools))
    suite.addTests(loader.loadTestsFromTestCase(TestEdgeCases))
    suite.addTests(loader.loadTestsFromTestCase(TestIntegration))

    runner = unittest.TextTestRunner(verbosity=2)
    result = runner.run(suite)

    print()
    print("=" * 70)
    print(f"Tests run: {result.testsRun}")
    print(f"Failures: {len(result.failures)}")
    print(f"Errors: {len(result.errors)}")
    print(f"Success: {result.wasSuccessful()}")
    print("=" * 70)

    return result.wasSuccessful()


if __name__ == "__main__":
    success = main()
    exit(0 if success else 1)
